char *transformAndConcat(char **stringList, int threshold)
{
    int count = 0;
    size_t total_len = 0;
    int i, pos, current_count;
    char *result;

    for (i = 0; stringList[i] != NULL; i++) {
        char *s = stringList[i];
        size_t len = strlen(s);
        if (len > threshold) {
            count++;
            total_len += len;
        }
    }

    if (count == 0) {
        char *empty = malloc(1);
        if (empty == NULL)
            return NULL;
        empty[0] = '\0';
        return empty;
    }

    total_len += count - 1;

    result = malloc(total_len + 1);
    if (result == NULL)
        return NULL;

    pos = 0;
    current_count = 0;

    for (i = 0; stringList[i] != NULL; i++) {
        char *s = stringList[i];
        size_t len = strlen(s);
        if (len > threshold) {
            strcpy(result + pos, s);
            pos += len;
            current_count++;
            if (current_count < count) {
                result[pos] = '\n';
                pos++;
            }
        }
    }

    result[pos] = '\0';

    return result;
}
