    const params = {};
    const pairs = queryString.split('&');
    for (let i = 0; i < pairs.length; i++) {
        const pair = pairs[i];
        let eqIndex = pair.indexOf('=');
        let key, value;
        if (eqIndex === -1) {
            key = pair;
            value = '';
