/// Merges overlapping intervals and returns non-overlapping intervals.
///
/// Given a vector of intervals represented as tuples (start, end), this function
/// sorts the intervals, then iterates through them to merge any overlapping or adjacent
/// intervals. The merged intervals are returned in ascending order.
///
/// # Arguments
/// * `intervals` - A vector of tuples where each tuple (start, end) represents an interval.
///
/// # Returns
/// A vector of merged non-overlapping intervals as tuples.
///
/// # Examples
/// ```
/// let intervals = vec![(1, 3), (2, 6), (8, 10), (15, 18)];
/// let merged = merge_intervals(intervals);
/// assert_eq!(merged, vec![(1, 6), (8, 10), (15, 18)]);
/// ```
fn merge_intervals(mut intervals: Vec<(i32, i32)>) -> Vec<(i32, i32)> {
    if intervals.is_empty() {
        return intervals;
    }
    intervals.sort_by(|a, b| a.0.cmp(&b.0));
    let mut merged = vec![intervals[0]];
    for current in intervals.into_iter().skip(1) {
        let last = merged.last_mut().unwrap();
        if current.0 <= last.1 {
            if current.1 > last.1 {
                last.1 = current.1;
            }
        } else {
            merged.push(current);
        }
    }
    merged
}
